   136→
   137→  if (!can_create_connection) {
   138→    host_->cluster().trafficStats()->upstream_cx_overflow_.inc();
   139→  }
   140→  // If we are at the connection circuit-breaker limit due to other upstreams having
   141→  // too many open connections, and this upstream has no connections, always create one, to
   142→  // prevent pending streams being queued to this upstream with no way to be processed.
   143→  if (can_create_connection || (ready_clients_.empty() && busy_clients_.empty() &&
   144→                                connecting_clients_.empty() && early_data_clients_.empty())) {
   145→    ENVOY_LOG(debug, "creating a new connection (connecting={})", connecting_clients_.size());
   146→    ActiveClientPtr client = instantiateActiveClient();
   147→    if (client.get() == nullptr) {
   148→      ENVOY_LOG(trace, "connection creation failed");
   149→      return ConnectionResult::FailedToCreateConnection;
   150→    }
   151→    ASSERT(client->state() == ActiveClient::State::Connecting);
   152→    ASSERT(std::numeric_limits<uint64_t>::max() - connecting_stream_capacity_ >=
   153→           static_cast<uint64_t>(client->currentUnusedCapacity()));
   154→    ASSERT(client->real_host_description_);
   155→    // Increase the connecting capacity to reflect the streams this connection can serve.
   156→    incrConnectingAndConnectedStreamCapacity(client->currentUnusedCapacity(), *client);
   157→    LinkedList::moveIntoList(std::move(client), owningList(client->state()));
   158→    return can_create_connection ? ConnectionResult::CreatedNewConnection
   159→                                 : ConnectionResult::CreatedButRateLimited;
   160→  } else {
   161→    ENVOY_LOG(trace, "not creating a new connection: connection constrained");
   162→    return ConnectionResult::NoConnectionRateLimited;
   163→  }
   164→}
   165→
   166→void ConnPoolImplBase::attachStreamToClient(Envoy::ConnectionPool::ActiveClient& client,
   167→                                            AttachContext& context) {
   168→  ASSERT(client.readyForStream());
   169→
   170→  Upstream::ClusterTrafficStats& traffic_stats = *host_->cluster().trafficStats();
   171→  if (client.state() == Envoy::ConnectionPool::ActiveClient::State::ReadyForEarlyData) {
   172→    traffic_stats.upstream_rq_0rtt_.inc();
   173→  }
   174→
   175→  if (enforceMaxRequests() && !host_->cluster().resourceManager(priority_).requests().canCreate()) {
   176→    ENVOY_LOG(debug, "max streams overflow");
   177→    onPoolFailure(client.real_host_description_, absl::string_view(),
   178→                  ConnectionPool::PoolFailureReason::Overflow, context);
   179→    traffic_stats.upstream_rq_pending_overflow_.inc();
   180→    return;
   181→  }
   182→  ENVOY_CONN_LOG(debug, "creating stream", client);
   183→
   184→  // Latch capacity before updating remaining streams.
   185→  uint64_t capacity = client.currentUnusedCapacity();
   186→  client.remaining_streams_--;
   187→  if (client.remaining_streams_ == 0) {
   188→    ENVOY_CONN_LOG(debug, "maximum streams per connection, start draining", client);
   189→    traffic_stats.upstream_cx_max_requests_.inc();
   190→    transitionActiveClientState(client, Envoy::ConnectionPool::ActiveClient::State::Draining);
   191→  } else if (capacity == 1) {
   192→    // As soon as the new stream is created, the client will be maxed out.
   193→    transitionActiveClientState(client, Envoy::ConnectionPool::ActiveClient::State::Busy);
   194→  }
   195→
   196→  // Decrement the capacity, as there's one less stream available for serving.
   197→  // For HTTP/3, the capacity is updated in newStreamEncoder.
   198→  if (trackStreamCapacity()) {
   199→    decrConnectingAndConnectedStreamCapacity(1, client);
   200→  }
   201→  // Track the new active stream.
   202→  state_.incrActiveStreams(1);
   203→  num_active_streams_++;
   204→  host_->stats().rq_total_.inc();
   205→  host_->stats().rq_active_.inc();
   206→  traffic_stats.upstream_rq_total_.inc();
   207→  traffic_stats.upstream_rq_active_.inc();
   208→  host_->cluster().resourceManager(priority_).requests().inc();
   209→
   210→  onPoolReady(client, context);
   211→}
   212→
   213→void ConnPoolImplBase::onStreamClosed(Envoy::ConnectionPool::ActiveClient& client,
   214→                                      bool delay_attaching_stream) {
   215→  ENVOY_CONN_LOG(debug, "destroying stream: {} remaining", client, client.numActiveStreams());
   216→  ASSERT(num_active_streams_ > 0);
   217→  state_.decrActiveStreams(1);
   218→  num_active_streams_--;
   219→  host_->stats().rq_active_.dec();
   220→  host_->cluster().trafficStats()->upstream_rq_active_.dec();
   221→  host_->cluster().resourceManager(priority_).requests().dec();
   222→  // We don't update the capacity for HTTP/3 as the stream count should only
   223→  // increase when a MAX_STREAMS frame is received.
   224→  if (trackStreamCapacity()) {
   225→    // If the effective client capacity was limited by concurrency, increase connecting capacity.
   226→    bool limited_by_concurrency =
   227→        client.remaining_streams_ > client.concurrent_stream_limit_ - client.numActiveStreams() - 1;
   228→    // The capacity calculated by concurrency could be negative if a SETTINGS frame lowered the
   229→    // number of allowed streams. In this case, effective client capacity was still limited by
   230→    // concurrency, compare client.concurrent_stream_limit_ and client.numActiveStreams() directly
   231→    // to avoid overflow.
   232→    bool negative_capacity = client.concurrent_stream_limit_ < client.numActiveStreams() + 1;
   233→    if (negative_capacity || limited_by_concurrency) {
   234→      incrConnectingAndConnectedStreamCapacity(1, client);
   235→    }
   236→  }
   237→  if (client.state() == ActiveClient::State::Draining && client.numActiveStreams() == 0) {
   238→    // Close out the draining client if we no longer have active streams.
   239→    client.close();
   240→  } else if (client.state() == ActiveClient::State::Busy && client.currentUnusedCapacity() > 0) {
   241→    if (!client.hasHandshakeCompleted()) {
   242→      transitionActiveClientState(client, ActiveClient::State::ReadyForEarlyData);
   243→      if (!delay_attaching_stream) {
   244→        onUpstreamReadyForEarlyData(client);
   245→      }
   246→    } else {
   247→      transitionActiveClientState(client, ActiveClient::State::Ready);
   248→      if (!delay_attaching_stream) {
   249→        onUpstreamReady();
   250→      }
   251→    }
   252→  }
   253→}
   254→
   255→ConnectionPool::Cancellable* ConnPoolImplBase::newStreamImpl(AttachContext& context,
   256→                                                             bool can_send_early_data) {
   257→  ASSERT(!is_draining_for_deletion_);
   258→  ASSERT(!deferred_deleting_);
   259→
   260→  ASSERT(static_cast<ssize_t>(connecting_stream_capacity_) ==
   261→         connectingCapacity(connecting_clients_) +
   262→             connectingCapacity(early_data_clients_)); // O(n) debug check.
   263→  if (!ready_clients_.empty()) {
   264→    ActiveClient& client = *ready_clients_.front();
   265→    ENVOY_CONN_LOG(debug, "using existing fully connected connection", client);
   266→    attachStreamToClient(client, context);
   267→    // Even if there's a ready client, we may want to preconnect to handle the next incoming stream.
   268→    tryCreateNewConnections();
   269→    return nullptr;
   270→  }
   271→
   272→  if (can_send_early_data && !early_data_clients_.empty()) {
   273→    ActiveClient& client = *early_data_clients_.front();
   274→    ENVOY_CONN_LOG(debug, "using existing early data ready connection", client);
   275→    attachStreamToClient(client, context);
   276→    // Even if there's an available client, we may want to preconnect to handle the next
   277→    // incoming stream.
   278→    tryCreateNewConnections();
   279→    return nullptr;
   280→  }
   281→
   282→  if (!host_->cluster().resourceManager(priority_).pendingRequests().canCreate()) {
   283→    ENVOY_LOG(debug, "max pending streams overflow");
   284→    onPoolFailure(nullptr, absl::string_view(), ConnectionPool::PoolFailureReason::Overflow,
   285→                  context);
   286→    host_->cluster().trafficStats()->upstream_rq_pending_overflow_.inc();
   287→    return nullptr;
   288→  }
   289→
   290→  ConnectionPool::Cancellable* pending = newPendingStream(context, can_send_early_data);
   291→  ENVOY_LOG(debug, "trying to create new connection");
   292→  ENVOY_LOG(trace, fmt::format("{}", *this));
   293→
   294→  auto old_capacity = connecting_stream_capacity_;
   295→  // This must come after newPendingStream() because this function uses the
   296→  // length of pending_streams_ to determine if a new connection is needed.
   297→  const ConnectionResult result = tryCreateNewConnections();
   298→  // If there is not enough connecting capacity, the only reason to not
   299→  // increase capacity is if the connection limits are exceeded.
   300→  ENVOY_BUG(pending_streams_.size() <= connecting_stream_capacity_ ||
   301→                connecting_stream_capacity_ > old_capacity ||
   302→                (result == ConnectionResult::NoConnectionRateLimited ||
   303→                 result == ConnectionResult::FailedToCreateConnection),
   304→            fmt::format("Failed to create expected connection: {}", *this));
   305→  if (result == ConnectionResult::FailedToCreateConnection) {
   306→    // This currently only happens for HTTP/3 if secrets aren't yet loaded.
   307→    // Trigger connection failure.
   308→    pending->cancel(Envoy::ConnectionPool::CancelPolicy::CloseExcess);
   309→    onPoolFailure(nullptr, absl::string_view(),
   310→                  ConnectionPool::PoolFailureReason::LocalConnectionFailure, context);
   311→    return nullptr;
   312→  }
   313→  return pending;
   314→}
