   316→bool ConnPoolImplBase::maybePreconnectImpl(float global_preconnect_ratio) {
   317→  ASSERT(!deferred_deleting_);
   318→  return tryCreateNewConnection(global_preconnect_ratio) == ConnectionResult::CreatedNewConnection;
