   621→PendingStream::PendingStream(ConnPoolImplBase& parent, bool can_send_early_data)
   622→    : parent_(parent), can_send_early_data_(can_send_early_data) {
   623→  Upstream::ClusterTrafficStats& traffic_stats = *parent_.host()->cluster().trafficStats();
   624→  traffic_stats.upstream_rq_pending_total_.inc();
   625→  traffic_stats.upstream_rq_pending_active_.inc();
