   276→  // Called by derived classes any time a stream is completed or destroyed for any reason.
   277→  void onStreamClosed(Envoy::ConnectionPool::ActiveClient& client, bool delay_attaching_stream);
   278→
   279→  Event::Dispatcher& dispatcher() { return dispatcher_; }
   280→  Upstream::ResourcePriority priority() const { return priority_; }
   281→  const Network::ConnectionSocket::OptionsSharedPtr& socketOptions() { return socket_options_; }
   282→  const Network::TransportSocketOptionsConstSharedPtr& transportSocketOptions() {
   283→    return transport_socket_options_;
   284→  }
   285→  bool hasPendingStreams() const { return !pending_streams_.empty(); }
   286→
   287→  void decrClusterStreamCapacity(uint32_t delta) {
   288→    state_.decrConnectingAndConnectedStreamCapacity(delta);
   289→  }
   290→  void incrClusterStreamCapacity(uint32_t delta) {
   291→    state_.incrConnectingAndConnectedStreamCapacity(delta);
   292→  }
   293→  void dumpState(std::ostream& os, int indent_level = 0) const {
   294→    const char* spaces = spacesForLevel(indent_level);
   295→    os << spaces << "ConnPoolImplBase " << this << DUMP_MEMBER(ready_clients_.size())
